import LocalAuthentication
import UIKit

class BiometricAuthentication {
    static let shared = BiometricAuthentication()
    private init() {}

    private let authenticatedKey = "isAuthenticated"

    var isAuthenticated: Bool {
        get {
            UserDefaults.standard.bool(forKey: authenticatedKey)
        }
        set {
            UserDefaults.standard.set(newValue, forKey: authenticatedKey)
        }
