    func authenticateUser(reason: String, completion: @escaping (Bool, LAError?) -> Void) {
        let context = LAContext()
        var error: NSError?

        if context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) {
            context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, authenticationError in
                DispatchQueue.main.async {
                    if success {
                        self.isAuthenticated = true
                        completion(true, nil)
                    } else {
                        self.isAuthenticated = false
                        completion(false, authenticationError as? LAError)
                    }
                }
            }
        } else {
            // Biometric authentication not available or not configured
            DispatchQueue.main.async {
                self.isAuthenticated = false
                completion(false, error as? LAError)
            }
        }
    }

    func resetAuthentication() {
        isAuthenticated = false
    }
}

